import React, { useMemo } from "react";
import { useData } from "../lib/DataContext";
import { Link } from "react-router-dom";
import { AlertTriangle, CheckCircle, Clock, Wrench, ChevronRight } from "lucide-react";
import { format, parseISO, isValid } from "date-fns";
import { es } from "date-fns/locale";

function statusBadge(s) {
  const map = {
    "Completado":   "badge-success",
    "En Progreso":  "badge-info",
    "Pendiente":    "badge-warn",
    "Cancelado":    "badge-danger",
  };
  return <span className={`badge ${map[s] || "badge-neutral"}`}>{s}</span>;
}

function priorityBadge(p) {
  const map = { Alta: "badge-danger", Media: "badge-warn", Baja: "badge-neutral" };
  return <span className={`badge ${map[p] || "badge-neutral"}`}>{p}</span>;
}

export default function Dashboard() {
  const { workOrders, equipment, timeEntries, mechanics, loading } = useData();

  const stats = useMemo(() => {
    const open    = workOrders.filter(w => w.status !== "Completado" && w.status !== "Cancelado").length;
    const urgent  = workOrders.filter(w => w.priority === "Alta" && w.status !== "Completado").length;
    const active  = equipment.filter(e => e.status === "Activo").length;
    const clocked = timeEntries.filter(t => t.clockIn && !t.clockOut).length;
    const totalHrs = timeEntries.reduce((sum, t) => sum + (parseFloat(t.hours) || 0), 0);
    return { open, urgent, active, clocked, totalHrs: totalHrs.toFixed(1) };
  }, [workOrders, equipment, timeEntries]);

  const recentOrders = useMemo(
    () => [...workOrders].sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)).slice(0, 6),
    [workOrders]
  );

  const activeEntries = useMemo(
    () => timeEntries.filter(t => t.clockIn && !t.clockOut),
    [timeEntries]
  );

  if (loading) return <div className="empty-state"><p>Cargando datos…</p></div>;

  return (
    <div>
      {/* Header */}
      <div className="page-header">
        <div>
          <h1 className="page-title">Panel Principal</h1>
          <p className="page-subtitle">
            {format(new Date(), "EEEE d 'de' MMMM, yyyy", { locale: es })}
          </p>
        </div>
        <Link to="/orders" className="btn btn-primary">
          + Nueva Orden
        </Link>
      </div>

      {/* KPI row */}
      <div className="grid-4 mb-24">
        <div className="stat-card" style={{ "--accent-line": "var(--warn)" }}>
          <span className="stat-label">Órdenes Abiertas</span>
          <span className="stat-value">{stats.open}</span>
          <span className="stat-sub">{stats.urgent} urgentes</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--danger)" }}>
          <span className="stat-label">Alta Prioridad</span>
          <span className="stat-value">{stats.urgent}</span>
          <span className="stat-sub">requieren atención</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--success)" }}>
          <span className="stat-label">Equipos Activos</span>
          <span className="stat-value">{stats.active}</span>
          <span className="stat-sub">de {equipment.length} en total</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--info)" }}>
          <span className="stat-label">Horas Totales</span>
          <span className="stat-value">{stats.totalHrs}</span>
          <span className="stat-sub">{stats.clocked} mecánicos activos ahora</span>
        </div>
      </div>

      <div className="grid-2" style={{ gap: 20, alignItems: "start" }}>
        {/* Recent work orders */}
        <div className="card" style={{ gridColumn: "1 / -1" }}>
          <div className="card-header">
            <span className="card-title">Órdenes Recientes</span>
            <Link to="/orders" className="btn btn-ghost btn-sm">
              Ver todas <ChevronRight size={14} />
            </Link>
          </div>
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Equipo</th>
                  <th>Trabajo</th>
                  <th>Mecánico</th>
                  <th>Prioridad</th>
                  <th>Estado</th>
                </tr>
              </thead>
              <tbody>
                {recentOrders.map(wo => (
                  <tr key={wo.id}>
                    <td><span className="text-mono text-muted" style={{ fontSize: 12 }}>{wo.id}</span></td>
                    <td style={{ fontWeight: 500 }}>{wo.equipmentName}</td>
                    <td style={{ color: "var(--text2)" }}>{wo.title}</td>
                    <td>{wo.mechanicName}</td>
                    <td>{priorityBadge(wo.priority)}</td>
                    <td>{statusBadge(wo.status)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Active clock-ins */}
        <div className="card">
          <div className="card-header">
            <span className="card-title">Mecánicos Trabajando</span>
            <span className="badge badge-success pulse">{activeEntries.length} activos</span>
          </div>
          {activeEntries.length === 0 ? (
            <div className="empty-state" style={{ padding: "30px 0" }}>
              <Clock size={32} />
              <p>Sin registros activos</p>
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              {activeEntries.map(te => (
                <div key={te.id} style={{
                  display: "flex", justifyContent: "space-between", alignItems: "center",
                  padding: "10px 14px",
                  background: "var(--bg3)",
                  borderRadius: "var(--radius)",
                  borderLeft: "2px solid var(--success)"
                }}>
                  <div>
                    <div style={{ fontWeight: 500, fontSize: 14 }}>{te.mechanicName}</div>
                    <div style={{ fontSize: 12, color: "var(--text3)", fontFamily: "var(--font-mono)" }}>
                      Orden: {te.workOrderId}
                    </div>
                  </div>
                  <div style={{ textAlign: "right" }}>
                    <div className="pulse" style={{ color: "var(--success)", fontSize: 12, fontFamily: "var(--font-mono)" }}>
                      ● EN CURSO
                    </div>
                    <div style={{ fontSize: 11, color: "var(--text3)" }}>
                      desde {te.clockIn?.split(" ")[1]}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Equipment alerts */}
        <div className="card">
          <div className="card-header">
            <span className="card-title">Alertas de Equipo</span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {equipment.filter(e => e.status === "En Reparación" || e.status === "Inactivo").map(eq => (
              <div key={eq.id} style={{
                display: "flex", alignItems: "center", gap: 12,
                padding: "10px 14px",
                background: "var(--bg3)",
                borderRadius: "var(--radius)",
                borderLeft: `2px solid ${eq.status === "En Reparación" ? "var(--warn)" : "var(--danger)"}`
              }}>
                <AlertTriangle size={16} color={eq.status === "En Reparación" ? "var(--warn)" : "var(--danger)"} />
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 14, fontWeight: 500 }}>{eq.name}</div>
                  <div style={{ fontSize: 11, color: "var(--text3)", fontFamily: "var(--font-mono)" }}>
                    {eq.status} · {eq.type}
                  </div>
                </div>
              </div>
            ))}
            {equipment.filter(e => e.status === "En Reparación" || e.status === "Inactivo").length === 0 && (
              <div style={{ display: "flex", alignItems: "center", gap: 10, color: "var(--success)", fontSize: 13 }}>
                <CheckCircle size={16} />
                Todos los equipos operativos
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
